import{_ as o}from"./plugin-vue_export-helper-c27b6911.js";import{r as n,o as p,c as t,e as r,a,b as c,d as e,f as i}from"./app-0d87a9df.js";const h={},d=a("p",null,"Alpha 混合是什么？简单的说的就是两种带透明度的图片叠加在一起展示，就是 Alpha 混合",-1),u=i(`<h2 id="常规-预乘" tabindex="-1"><a class="header-anchor" href="#常规-预乘" aria-hidden="true">#</a> 常规/预乘？</h2><h3 id="常规alpha混合" tabindex="-1"><a class="header-anchor" href="#常规alpha混合" aria-hidden="true">#</a> 常规Alpha混合</h3><p>常规Alpha混合是指直接使用原始的非预乘Alpha值进行图像混合。在这种混合方式下，对于每个像素的RGB分量和Alpha值，都分别与背景进行混合计算。常规Alpha混合在某些情况下可能导致混合结果的颜色不准确或边缘出现锯齿状的伪像。</p><h3 id="预乘alpha混合" tabindex="-1"><a class="header-anchor" href="#预乘alpha混合" aria-hidden="true">#</a> 预乘Alpha混合</h3><p>预乘Alpha混合是一种常见的Alpha混合方式，它使用预乘Alpha值来表示像素的透明度信息。在预乘Alpha混合中，图像的RGB（红绿蓝）分量被乘以Alpha值，然后再与背景进行混合。这种方式可以提高混合的效率和质量，特别是在图像中存在半透明边缘的情况下。预乘Alpha混合通常用于实时图形应用中，如视频游戏和计算机动画。</p><p>使用alpha预乘方式混合出来的结果图片也是alpha预乘的。所以在显示此结果图片时应该使用(One,OneMinusSrcAlpha)对其进行绘制。</p><h2 id="代码参考" tabindex="-1"><a class="header-anchor" href="#代码参考" aria-hidden="true">#</a> 代码参考</h2><div class="language-typescript line-numbers-mode" data-ext="ts"><pre class="language-typescript"><code><span class="token comment">// 常规Alpha混合</span>
<span class="token keyword">let</span> result_color <span class="token operator">=</span> color <span class="token operator">*</span> alpha <span class="token operator">+</span> color2 <span class="token operator">*</span> <span class="token punctuation">(</span><span class="token number">1</span> <span class="token operator">-</span> alpha<span class="token punctuation">)</span>

<span class="token comment">// 预乘Alpha混合</span>
<span class="token keyword">let</span> premultiplied_color <span class="token operator">=</span> color <span class="token operator">*</span> alpha
<span class="token keyword">let</span> result_color <span class="token operator">=</span> premultiplied_color <span class="token operator">+</span> color2 <span class="token operator">*</span> <span class="token punctuation">(</span><span class="token number">1</span> <span class="token operator">-</span> alpha<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>color：源像素</li><li>color2：背景像素</li><li>alpha：源像素的透明度值（0-1）</li></ul><hr><p>参考：</p>`,11),m={href:"https://www.cnblogs.com/wantnon/p/5342359.html",target:"_blank",rel:"noopener noreferrer"},_=a("hr",null,null,-1),k=a("h3",null,"📣 觉得很赞？分享给你的朋友吧！",-1);function v(b,A){const s=n("ExternalLinkIcon"),l=n("Share");return p(),t("div",null,[d,r(" more "),u,a("ul",null,[a("li",null,[a("a",m,[c("https://www.cnblogs.com/wantnon/p/5342359.html"),e(s)])])]),_,k,e(l,{services:"qq,qrcode",colorful:""})])}const x=o(h,[["render",v],["__file","1.html.vue"]]);export{x as default};
